prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  ?modelName
  (COUNT(DISTINCT ?choreo) AS ?choreoCount)
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?start) AS ?startCount)
  (COUNT(DISTINCT ?end) AS ?endCount)
  (COUNT(DISTINCT ?gateway) AS ?gatewayCount)
  (COUNT(DISTINCT ?seqFlow) AS ?seqFlowCount)
  (COUNT(DISTINCT ?msgFlow) AS ?msgFlowCount)
  (COUNT(DISTINCT ?msg) AS ?messageCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "3d0f07f9b84c4e31bbca562f472c8885" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL {
    ?definitions tai:belongsTo ?model .
    ?choreo a bboExt:Choreography ;
            tai:belongsTo ?definitions .
  }
  OPTIONAL {
    ?choreo a bboExt:Choreography .
    ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?end a bboExt:EndEvent ; tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?gateway a ?gType ; tai:belongsTo ?choreo .
    FILTER(?gType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  }
  OPTIONAL {
    ?seqFlow a bbo:SequenceFlow ; tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?msgFlow a bboExt:MessageFlow ; tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?msg a bboExt:Message ; tai:belongsTo ?choreo .
  }
}
GROUP BY ?model ?modelName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  ?modelName
  ?origId
  ?normId
  ?orgId
  ?created
WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    ?org tai:organizationId ?orgId .
  }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(
    (
      EXISTS { ?model tai:normalizedId "3d0f07f9b84c4e31bbca562f472c8885" }
    )
    ||
    EXISTS { ?model tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" }
    ||
    EXISTS { ?model tai:originalId ?anyId . FILTER(?anyId = "3d0f07f9b84c4e31bbca562f472c8885") }
    ||
    EXISTS { ?model tai:normalizedId ?anyId . FILTER(?anyId = "3d0f07f9b84c4e31bbca562f472c8885") }
    )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?choreo
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?start) AS ?startCount)
  (COUNT(DISTINCT ?end) AS ?endCount)
  (COUNT(DISTINCT ?gw) AS ?gatewayCount)
  (COUNT(DISTINCT ?seqFlow) AS ?seqFlowCount)
  (COUNT(DISTINCT ?msgFlow) AS ?msgFlowCount)
  (COUNT(DISTINCT ?msg) AS ?messageCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" .
  ?model tai:belongsTo ?org .
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?end a bboExt:EndEvent ; tai:belongsTo ?choreo . }
  OPTIONAL {
    ?gw a ?gType ;
        tai:belongsTo ?choreo .
    FILTER(?gType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  }
  OPTIONAL { ?seqFlow a bbo:SequenceFlow ; tai:belongsTo ?choreo . }
  OPTIONAL { ?msgFlow a bboExt:MessageFlow ; tai:belongsTo ?choreo . }
  OPTIONAL { ?msg a bboExt:Message ; tai:belongsTo ?choreo . }
}
GROUP BY ?choreo
ORDER BY DESC(?taskCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?participant) AS ?participantCount)
  (COUNT(DISTINCT ?loopNone) AS ?tasksWithLoopNone)
  (COUNT(DISTINCT ?loopOther) AS ?tasksWithNonNoneLoop)
  (COUNT(DISTINCT ?msgFlowNoRef) AS ?msgFlowsMissingMessageRef)
  (COUNT(DISTINCT ?msgFlowHasRef) AS ?msgFlowsWithMessageRef)
  (COUNT(DISTINCT ?msgTargetExists) AS ?msgFlowsTargetExists)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" .
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?definitions .

  OPTIONAL { 
    ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo ; bboExt:loopType ?loopType .
    BIND(IF(?loopType = "None", ?task, UNDEF) AS ?loopNone)
    BIND(IF(?loopType != "None", ?task, UNDEF) AS ?loopOther)
  }

  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          tai:belongsTo ?choreo ;
          bboExt:initiatingParticipantRef ?partRef .
    ?participant a bboExt:Participant ; tai:belongsTo ?choreo ;
                 bbo:name ?participantName .
    FILTER(STRENDS(STR(?participant), ?partRef))
  }

  OPTIONAL {
    ?msgFlow a bboExt:MessageFlow ; tai:belongsTo ?choreo .
    OPTIONAL { ?msgFlow bboExt:messageRef ?messageRef . }
    BIND(IF(!BOUND(?messageRef), ?msgFlow, UNDEF) AS ?msgFlowNoRef)
    BIND(IF(BOUND(?messageRef), ?msgFlow, UNDEF) AS ?msgFlowHasRef)

    OPTIONAL { ?target a bboExt:ChoreographyTask ; tai:belongsTo ?choreo ; bbo:id ?tid . }

    # Check existence of message-flow target by matching the stored string to the suffix of the target's URI
    OPTIONAL {
      ?targetAny a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .
      FILTER(STRENDS(STR(?targetAny), STR(?msgFlow)))
    }
    BIND(UNDEF AS ?msgTargetExists)
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?participant) AS ?participantCount)
  (SUM(?isLoopNone) AS ?tasksWithLoopNone)
  (SUM(?isLoopOther) AS ?tasksWithNonNoneLoop)
  (SUM(?isMsgFlowNoRef) AS ?msgFlowsMissingMessageRef)
  (SUM(?isMsgFlowHasRef) AS ?msgFlowsWithMessageRef)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" .

  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?definitions .

  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          tai:belongsTo ?choreo ;
          bboExt:loopType ?loopType .
    BIND(IF(?loopType = "None", 1, 0) AS ?isLoopNone)
    BIND(IF(?loopType != "None", 1, 0) AS ?isLoopOther)
  }

  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          tai:belongsTo ?choreo ;
          bboExt:initiatingParticipantRef ?partRef .
    ?participant a bboExt:Participant ; tai:belongsTo ?choreo ; bbo:name ?participantName .
    FILTER(STRENDS(STR(?participant), ?partRef))
  }

  OPTIONAL {
    ?msgFlow a bboExt:MessageFlow ; tai:belongsTo ?choreo .
    OPTIONAL { ?msgFlow bboExt:messageRef ?messageRef . }
    BIND(IF(BOUND(?messageRef), 0, 1) AS ?isMsgFlowNoRef)
    BIND(IF(BOUND(?messageRef), 1, 0) AS ?isMsgFlowHasRef)
  }
}
GROUP BY ?model
LIMIT 25
